#include<bits/stdc++.h>
using namespace std;
long long n,m,c,a[1005][1005],ma=-2e17,x,y;
int main() {
	cin>>n>>m>>c;
	for(int i=1; i<=n; i++){
		for(int j=1; j<=m; j++) {
			cin>>x;
			a[i][j]=a[i-1][j]+a[i][j-1]-a[i-1][j-1]+x;
		}
	}
	for(int i=1; i<=n-c+1; i++){
		for(int j=1; j<=m-c+1; j++) {
			if(ma<a[i+c-1][j+c-1]-a[i+c-1][j-1]-a[i-1][j+c-1]+a[i-1][j-1]) {
				ma=a[i+c-1][j+c-1]-a[i+c-1][j-1]-a[i-1][j+c-1]+a[i-1][j-1];
				x=i;
				y=j;

			}
		}
	}
	cout<<x<<" "<<y;
	return 0;
}
